begin;

insert into public.quiz_topics (
  slug,
  title,
  short_title,
  subtitle,
  description,
  hero_copy,
  share_title,
  share_description,
  icon,
  theme_color,
  theme_color_soft,
  theme_ink,
  theme_glow,
  status,
  locale,
  question_pool_size,
  questions_per_session,
  axis_config,
  tag_labels,
  result_theme
) values (
  'personality-type',
  '你的人格節奏偏向哪一型？',
  '人格節奏',
  '你理解世界、安排自己的方式，比外向或內向更有層次。',
  '從日常安排、變動反應與第一直覺裡，看見你的個性骨架。',
  '有些人先拆解，有些人先感受；有些人需要結構，有些人活在流動裡。這份測驗會照出你習慣怎麼跟世界對話。',
  '人格節奏心理測驗',
  '測出你理解世界與安排自己的心理節奏。',
  '◎',
  '#a76d53',
  '#e7c2af',
  '#241914',
  'rgba(167,109,83,0.28)',
  'active',
  'zh-TW',
  32,
  8,
  '{"axes":[{"key":"processing_style","leftKey":"analytical","leftLabel":"分析取向","leftShort":"分析","leftStrength":"把複雜狀況拆成可處理的部分","leftBlindSpot":"你可能會把感覺延後到太後面","leftGrowth":"在分析之前先承認自己的第一反應","rightKey":"intuitive","rightLabel":"直覺取向","rightShort":"直覺","rightStrength":"很快讀到氣氛與隱性方向","rightBlindSpot":"你有時會先跟著感覺走，再補理由","rightGrowth":"讓感覺成形後，再補一個現實檢查"},{"key":"rhythm_style","leftKey":"structured","leftLabel":"有結構","leftShort":"結構","leftStrength":"替混亂建立穩定順序","leftBlindSpot":"你可能會對臨時變化太早緊繃","leftGrowth":"替計畫預留一點彈性空間","rightKey":"spontaneous","rightLabel":"即興流動","rightShort":"即興","rightStrength":"在變動裡保有活力與創意","rightBlindSpot":"你有時會把穩定感交給明天的自己","rightGrowth":"讓靈感有地方落地，感覺會更容易成為真實行動"}]}'::jsonb,
  '{"grounded":"穩住節奏","curiosity":"好奇心","control_need":"掌控感","openness":"開放度","recovery":"回彈力","sensitivity":"敏感度"}'::jsonb,
  '{"icon":"◎","shortTitle":"人格節奏","themeColor":"#a76d53","themeColorSoft":"#e7c2af","themeInk":"#241914","themeGlow":"rgba(167,109,83,0.28)","shareTitle":"人格節奏心理測驗","shareDescription":"測出你理解世界與安排自己的心理節奏。"}'::jsonb
) on conflict (slug) do update set
  title = excluded.title,
  short_title = excluded.short_title,
  subtitle = excluded.subtitle,
  description = excluded.description,
  hero_copy = excluded.hero_copy,
  share_title = excluded.share_title,
  share_description = excluded.share_description,
  icon = excluded.icon,
  theme_color = excluded.theme_color,
  theme_color_soft = excluded.theme_color_soft,
  theme_ink = excluded.theme_ink,
  theme_glow = excluded.theme_glow,
  locale = excluded.locale,
