  questions_per_session = excluded.questions_per_session,
  axis_config = excluded.axis_config,
  tag_labels = excluded.tag_labels,
  result_theme = excluded.result_theme,
  status = excluded.status;

insert into public.questions (
  topic_id,
  question_code,
  prompt,
  context_hint,
  sort_order,
  status
) values (
  (select id from public.quiz_topics where slug = 'personality-type'),
  'PT-01',
  '當行程突然被打亂時，你最先冒出的反應通常比較像哪一種？',
