  1,
  'active'
) on conflict (topic_id, question_code) do update set
  prompt = excluded.prompt,
  context_hint = excluded.context_hint,
  sort_order = excluded.sort_order,
  status = excluded.status;

insert into public.question_options (
  question_id,
