insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'personality-type'),
  'quadrant_ll',
  '冷靜佈局者',
  '在安排自己與理解世界這件事上，你通常會先用分析取向讀懂現場，再用有結構決定自己的節奏。你有彈性，也有自己獨特的安心定義。',
  ARRAY['你常能把複雜狀況拆成可處理的部分。', '你也擅長替混亂建立穩定順序。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴分析時，你可能會把感覺延後到太後面。', '當壓力升高時，你可能會對臨時變化太早緊繃。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的分析優勢，同時刻意借一點直覺的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替結構留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你的人格節奏偏向哪一型？」中呈現 分析取向 與 有結構 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"analytical","axis2":"structured"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

