  '#9d668a',
  '#e3c4d9',
  '#23161f',
  'rgba(157,102,138,0.25)',
  'active',
  'zh-TW',
  32,
  8,
  '{"axes":[{"key":"emotion_expression","leftKey":"internalized","leftLabel":"內收處理","leftShort":"內收","leftStrength":"先在心裡整理自己的真實感受","leftBlindSpot":"外面的人可能看不見你其實已經很滿","leftGrowth":"在還能說清楚時，先吐露一點點真實","rightKey":"expressive","rightLabel":"外放表達","rightShort":"外放","rightStrength":"讓情緒有出口，不讓它悶成結","rightBlindSpot":"你有時會在情緒還沒落地前，就先把它丟向外面","rightGrowth":"先確認你要的是被懂，還是只是要把感受釋放掉"},{"key":"emotion_regulation","leftKey":"self_soothing","leftLabel":"自我緩衝","leftShort":"自我緩衝","leftStrength":"替自己找回節奏，不急著反應","leftBlindSpot":"你可能太會自己吞，別人不知道該怎麼靠近你","leftGrowth":"練習把安靜照顧自己，和允許別人陪你，放在同一張地圖上","rightKey":"reactive","rightLabel":"即時反應","rightShort":"即時反應","rightStrength":"很誠實地反映當下的衝擊與感受","rightBlindSpot":"情緒來得快時，你可能會先被浪頭推著走","rightGrowth":"先替情緒命名，再決定要不要立刻回應"}]}'::jsonb,
  '{"softness":"柔軟感","intensity":"情緒張力","tenderness":"被理解需求","privacy":"情緒隱私","release":"釋放需求","recovery":"情緒回彈"}'::jsonb,
  '{"icon":"◔","shortTitle":"情緒慣性","themeColor":"#9d668a","themeColorSoft":"#e3c4d9","themeInk":"#23161f","themeGlow":"rgba(157,102,138,0.25)","shareTitle":"情緒慣性心理測驗","shareDescription":"測出你情緒升起時最常啟動的保護模式。"}'::jsonb
