insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'emotional-patterns'),
  'quadrant_ll',
  '安靜沉澱者',
  '在情緒升起、停留與退場這件事上，你通常會先用內收處理讀懂現場，再用自我緩衝決定自己的節奏。你的情緒很細緻，表達和保護感受的方式也很有層次。',
  ARRAY['你常能先在心裡整理自己的真實感受。', '你也擅長替自己找回節奏，不急著反應。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴內收時，外面的人可能看不見你其實已經很滿。', '當壓力升高時，你可能太會自己吞，別人不知道該怎麼靠近你。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的內收優勢，同時刻意借一點外放的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替自我緩衝留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你的情緒慣性最像哪一種？」中呈現 內收處理 與 自我緩衝 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"internalized","axis2":"self_soothing"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

