insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'stress-response'),
  'quadrant_ll',
  '壓力佈防者',
  '在高壓情境與求生反應這件事上，你通常會先用先動起來讀懂現場，再用往內吞壓決定自己的節奏。你的壓力模式帶著保護你的用意。',
  ARRAY['你常能在混亂中盡快找到可做的事。', '你也擅長把外界干擾收住，不讓場面更亂。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴先動時，你有時會靠一直做來掩蓋自己其實已經很緊繃。', '當壓力升高時，別人不一定知道你已經撐到哪裡。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的先動優勢，同時刻意借一點先停的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替往內吞留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「壓力來時，你最常啟動哪種反應？」中呈現 先動起來 與 往內吞壓 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"proactive","axis2":"internalize_stress"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

