insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'decision-making-style'),
  'quadrant_ll',
  '冷靜定盤者',
  '在做選擇與承擔結果這件事上，你通常會先用審慎衡量讀懂現場，再用自己定奪決定自己的節奏。你做決定的速度與節奏，反映你想確認的東西不一樣。',
  ARRAY['你常能把條件與風險看得比較完整。', '你也擅長不容易被外界意見輕易帶走。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴衡量時，你可能會在資訊還沒完美前遲遲不肯動。', '當壓力升高時，你可能會把求助誤會成搖擺。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的衡量優勢，同時刻意借一點直感的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替自己定留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你做決定時，習慣靠哪套系統？」中呈現 審慎衡量 與 自己定奪 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"deliberate","axis2":"independent"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

