insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'relationship-style'),
  'quadrant_ll',
  '坦白安定者',
  '在靠近、受傷與修復關係這件事上，你通常會先用安心靠近讀懂現場，再用直接表達決定自己的節奏。你在關係裡最先保護的東西，很值得被溫柔理解。',
  ARRAY['你常能在靠近時保有穩定感，不必一直猜。', '你也擅長能把需求和不舒服講得比較清楚。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴安心靠近時，你有時會低估別人其實比你更需要被安撫。', '當壓力升高時，你有時會把誠實講得太快，讓對方來不及消化。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的安心靠近優勢，同時刻意借一點先設防的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替直接留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「在關係裡，你最常用哪種靠近方式？」中呈現 安心靠近 與 直接表達 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"secure","axis2":"direct"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

