insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'hidden-fears'),
  'quadrant_ll',
  '敏感佈防者',
  '在害怕暴露、失敗與失控這件事上，你通常會先用害怕被拒絕讀懂現場，再用用掌控保護自己決定自己的節奏。很多時候你以為自己只是謹慎，其實那也是害怕在說話。',
  ARRAY['你常能對人際溫度與細微變化特別敏感。', '你也擅長靠安排與預備降低不確定感。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴怕被拒絕時，你可能太早把模糊訊號解讀成否定。', '當壓力升高時，當你太想掌控時，心會比事情還累。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的怕被拒絕優勢，同時刻意借一點怕失敗的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替掌控保護留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你的隱性恐懼最常躲在哪裡？」中呈現 害怕被拒絕 與 用掌控保護自己 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"rejection_sensitive","axis2":"control_seeking"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

