  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'hidden-fears'),
  'quadrant_rr',
  '低調避險者',
  '在害怕暴露、失敗與失控這件事上，你通常會先用害怕失敗讀懂現場，再用用退開保護自己決定自己的節奏。很多時候你以為自己只是謹慎，其實那也是害怕在說話。',
  ARRAY['你常能對成果、風險與後果有高度警覺。', '你也擅長知道自己過載時需要拉開距離。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴怕失敗時，你有時會因為怕輸而不敢真正投入。', '當壓力升高時，你可能在關係或機會真正靠近前就先抽離。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的怕失敗優勢，同時刻意借一點怕被拒絕的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替退開保護留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你的隱性恐懼最常躲在哪裡？」中呈現 害怕失敗 與 用退開保護自己 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"failure_sensitive","axis2":"withdrawal"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
