) values (
  'motivation-style',
  '你最容易被哪一種動機點燃？',
  '動機風格',
  '你的動力有自己的火種，不同時候會需要不同燃料。',
  '從起步方式、長期推進與回饋需求，看見你真正的驅動源。',
  '有些人要看見成果才有力，有些人要先感到值得；有人靠穩定，有人靠爆發。這份測驗會照出你真正的點火方式。',
  '動機風格心理測驗',
  '看見你最容易被什麼樣的內在燃料推著走。',
  '✦',
  '#92804a',
  '#e4dbb3',
  '#211d13',
  'rgba(146,128,74,0.29)',
  'active',
  'zh-TW',
  32,
  8,
  '{"axes":[{"key":"motivation_source","leftKey":"achievement_driven","leftLabel":"成就驅動","leftShort":"成就","leftStrength":"被目標、成果與可見進步推著走","leftBlindSpot":"當外在回報變少時，你可能很快失去心情","leftGrowth":"讓成果感和價值感同時存在，你會走得更久","rightKey":"meaning_driven","rightLabel":"意義驅動","rightShort":"意義","rightStrength":"只要覺得值得，就能投入得很深","rightBlindSpot":"如果感覺不對味，你可能很難強迫自己前進","rightGrowth":"替價值感找一個具體結構，不要全靠感受維持"},{"key":"motivation_rhythm","leftKey":"steady","leftLabel":"穩定推進","leftShort":"穩推","leftStrength":"靠節奏把長期事情慢慢做出來","leftBlindSpot":"有時你會為了穩而少了一點熱度與冒險","leftGrowth":"在穩定之外，允許一點偶爾的火花幫你加速","rightKey":"pulse_driven","rightLabel":"脈衝爆發","rightShort":"爆發","rightStrength":"一旦被點燃，能在短時間內衝出很強的動能","rightBlindSpot":"你有時會把後續維持丟給未來的自己","rightGrowth":"把爆發力接回日常節奏，別讓靈感只剩高峰"}]}'::jsonb,
  '{"reward":"回饋需求","meaning":"意義感","pace":"節奏感","spark":"點火感","endurance":"持續力","comparison":"比較敏感"}'::jsonb,
  '{"icon":"✦","shortTitle":"動機風格","themeColor":"#92804a","themeColorSoft":"#e4dbb3","themeInk":"#211d13","themeGlow":"rgba(146,128,74,0.29)","shareTitle":"動機風格心理測驗","shareDescription":"看見你最容易被什麼樣的內在燃料推著走。"}'::jsonb
) on conflict (slug) do update set
  title = excluded.title,
  short_title = excluded.short_title,
