  context_hint,
  sort_order,
  status
) values (
  (select id from public.quiz_topics where slug = 'motivation-style'),
  'MS-14',
  '遇到沒有人催你、也沒有人盯進度這種狀態，你多半怎麼和自己的動力相處？',
