    from public.questions
    inner join public.quiz_topics on quiz_topics.id = questions.topic_id
    where quiz_topics.slug = 'motivation-style'
      and questions.question_code = 'MS-32'
  ),
  'D',
  '我想被某種真正在乎的感覺重新點亮。',
  '{"quadrant":"rr","scores":{"meaning_driven":2,"pulse_driven":2},"tags":{"spark":1,"meaning":1}}'::jsonb,
  4
) on conflict (question_id, option_key) do update set
  option_text = excluded.option_text,
  trait_weights = excluded.trait_weights,
  option_order = excluded.option_order;

insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'motivation-style'),
  'quadrant_ll',
  '穩定攻頂者',
  '在起步、推進與維持動力這件事上，你通常會先用成就驅動讀懂現場，再用穩定推進決定自己的節奏。你的動力需要適合你的燃料與節奏。',
  ARRAY['你常能被目標、成果與可見進步推著走。', '你也擅長靠節奏把長期事情慢慢做出來。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴成就時，當外在回報變少時，你可能很快失去心情。', '當壓力升高時，有時你會為了穩而少了一點熱度與冒險。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的成就優勢，同時刻意借一點意義的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替穩推留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你最容易被哪一種動機點燃？」中呈現 成就驅動 與 穩定推進 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"achievement_driven","axis2":"steady"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

