insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'motivation-style'),
  'balanced_integration',
  '動機整流者',
  '你有能力用不只一套本能生活。面對起步、推進與維持動力，你能在成就驅動與意義驅動之間切換，也能在穩定推進與脈衝爆發之間找到自己的比例。',
  ARRAY['你比多數人更能同時看見兩種需求，不急著把自己塞進單一標籤。', '你能在穩定與流動、理性與感受之間找到彼此合作的方法。', '你的成熟感來自懂得辨認情緒，也知道什麼時候該換工具。']::text[],
  ARRAY['因為你看得到很多面向，有時反而比較晚承認自己真正偏向哪裡。', '你容易把「我都能理解」誤當成「我已經做出選擇」。', '當情境很模糊時，你可能會先維持平衡，卻延後真正的行動。']::text[],
  ARRAY['把平衡當作優勢，但不要讓平衡變成拖延表態的理由。', '在重要時刻，先問自己：今天我最想保護的是什麼？', '允許自己短暫偏向某一邊，因為清楚選擇有時比漂亮平衡更重要。']::text[],
  '這個人在「你最容易被哪一種動機點燃？」中呈現高度整合型結果。請寫一段 80 到 120 字的中文鏡像洞察，語氣溫柔、清晰、像被看懂。',
  '{"kind":"balanced_integration"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'motivation-style'),
  'balanced_bridge',
  '節奏策動者',
  '你有一條很穩的主軸，也在另一條主軸上保留彈性。這讓你在起步、推進與維持動力裡，看起來既不僵硬，也不會完全被情境牽著走。',
  ARRAY['你知道自己真正不能退讓的那一面，也知道哪裡可以變通。', '比起死守風格，你更擅長把自己的狀態調到剛剛好。', '你常能在不失去自己的前提下，跟情境做出合作。']::text[],
  ARRAY['別人可能以為你什麼都能適應，卻看不到你其實也會累。', '你有時會把彈性優先用來照顧場面，自己的需要也值得被排進來。', '當那條穩定主軸被碰撞時，你的反應可能比平常更強。']::text[],
  ARRAY['繼續保留你的調頻能力，但也替自己設一個不需要再撐的界線。', '別只問自己能不能適應，也要問值不值得你適應。', '在關鍵關係或選擇裡，把你的主軸說清楚，會比默默配合更輕鬆。']::text[],
  '這個人在「你最容易被哪一種動機點燃？」中呈現橋接型結果。請補一段 80 到 120 字的鏡像洞察，讓人感覺被理解但不被定型。',
  '{"kind":"balanced_bridge"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'motivation-style'),
  'tension_mirror',
  '動力斷續者',
  '你的內在同時有兩套很有力量的需求在拉扯。你能感受到起步、推進與維持動力裡彼此衝突的兩邊，所以常常比別人更細膩，也更容易內耗。',
  ARRAY['你的感受很有層次，所以你也比很多人更能理解複雜的感受。', '你對矛盾特別敏感，這讓你看得深，也不容易隨便自欺。', '當你站穩之後，你會比單一路線的人更有厚度。']::text[],
  ARRAY['因為每一邊都是真的，你可能會在選擇前先被自己的拉扯耗掉。', '你容易把矛盾解讀成自己不夠成熟，其實那更像是兩個重要需求都在說話。', '當壓力很大時，你可能同時想靠近又想退開，讓自己更困惑。']::text[],
  ARRAY['先不要逼自己立刻統一，只要先替兩邊都取一個名字。', '當你感到拉扯時，先分辨現在是害怕失去，還是害怕被困住。', '給內在衝突一點文字和空間，通常會比較快看見路。']::text[],
  '這個人在「你最容易被哪一種動機點燃？」中呈現高拉扯、鏡像型結果。請寫一段 80 到 120 字的中文鏡像洞察，像在替他把混亂說成人話。',
  '{"kind":"tension_mirror"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'motivation-style'),
  'tension_pivot',
  '火力調整者',
  '你正在兩種重要需求之間找新的比例。這段調整代表你已經長到不能再只靠舊方法活著，所以在起步、推進與維持動力上會特別有「明明知道，卻還在調整」的感覺。',
  ARRAY['你開始能看見自己正在長出新的版本，不必再用非黑即白理解自己。', '你對轉換時刻很敏感，所以也比較能捕捉真正的變化。', '你正在替新的重心找位置，節奏會慢慢穩下來。']::text[],
  ARRAY['轉換期很容易讓你誤會自己退步，實際上你只是還沒長出新節奏。', '你可能一邊想往前，一邊又想維持熟悉感，於是卡在中間。', '如果外界又急又吵，你會更難分辨哪個聲音是你自己的。']::text[],
  ARRAY['把轉換期當成過程，不要急著把自己判成矛盾。', '先選一個最想保護的核心，再讓其他變化慢慢跟上。', '當你感覺自己卡住時，回頭看最近哪些事情其實已經不一樣了。']::text[],
  '這個人在「你最容易被哪一種動機點燃？」中呈現轉換期、樞紐型結果。請寫一段 80 到 120 字的鏡像洞察，讓人感覺被安放、被理解，避免分析感。',
  '{"kind":"tension_pivot"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

