    from public.questions
    inner join public.quiz_topics on quiz_topics.id = questions.topic_id
    where quiz_topics.slug = 'social-behavior'
      and questions.question_code = 'SB-32'
  ),
  'D',
  '我在意的是能量要流得動，不要卡在尷尬裡。',
  '{"quadrant":"rr","scores":{"performative":2,"expansive":2},"tags":{"agility":1,"stamina":1}}'::jsonb,
  4
) on conflict (question_id, option_key) do update set
  option_text = excluded.option_text,
  trait_weights = excluded.trait_weights,
  option_order = excluded.option_order;

insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'social-behavior'),
  'quadrant_ll',
  '靜水觀察者',
  '在進入社交、維持存在與回收能量這件事上，你通常會先用觀察進場讀懂現場，再用選擇性靠近決定自己的節奏。你在場的方式有自己的節奏與溫度。',
  ARRAY['你常能先讀懂場域，再決定自己怎麼放進去。', '你也擅長把能量留給真正想連結的人。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴觀察時，別人可能以為你沒感覺，其實你只是還沒進場。', '當壓力升高時，你可能錯過一些其實值得打開的連結。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的觀察優勢，同時刻意借一點存在感的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替選擇性留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你的社交行為更偏向哪一種節奏？」中呈現 觀察進場 與 選擇性靠近 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"observant","axis2":"selective"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

