insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'thinking-patterns'),
  'quadrant_ll',
  '精準拆解者',
  '在理解訊息與看見重點這件事上，你通常會先用邏輯辨識讀懂現場，再用細節先行決定自己的節奏。你的腦習慣先看見某一種線索，這讓你的思考很有辨識度。',
  ARRAY['你常能先找因果、漏洞與可驗證的脈絡。', '你也擅長能從具體訊號看出真正的差別。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴邏輯時，你可能會把模糊但重要的感受訊號放得太後面。', '當壓力升高時，你可能在細節裡停太久，錯過大方向的流動。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的邏輯優勢，同時刻意借一點直覺的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替細節留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你的思考模式更偏向哪一邊？」中呈現 邏輯辨識 與 細節先行 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"logical","axis2":"detail_first"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

