insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'inner-conflicts'),
  'quadrant_ll',
  '穩住守心者',
  '在穩定、自由、保護與表達之間的拉扯這件事上，你通常會先用想先穩住讀懂現場，再用先保護自己決定自己的節奏。你覺得自己矛盾的地方，常常其實是兩種真實需要都很重要。',
  ARRAY['你常能在變動裡替自己保住基本安全感。', '你也擅長知道什麼不能隨便交出去。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴穩住時，你可能會把想冒險的那一面壓得太久。', '當壓力升高時，你可能讓很多真正重要的話永遠停在心裡。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的穩住優勢，同時刻意借一點活開的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替保護留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你心裡最常打架的是哪兩邊？」中呈現 想先穩住 與 先保護自己 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"stability_seeking","axis2":"self_protective"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

