insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'self-discipline-vs-impulse'),
  'quadrant_ll',
  '長線執行者',
  '在當下舒服、長期目標與自我管理這件事上，你通常會先用自律牽引讀懂現場，再用長期取向決定自己的節奏。你的意志需要適合你的支撐方式。',
  ARRAY['你常能能為未來的自己先做安排。', '你也擅長願意為更遠的目標延遲滿足。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴自律時，你有時會把鬆一下也看得太像失守。', '當壓力升高時，你可能常常只記得應該，忘了自己也需要獎勵。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的自律優勢，同時刻意借一點衝動的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替長期留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你在自律與衝動之間偏向哪一邊？」中呈現 自律牽引 與 長期取向 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"disciplined","axis2":"long_term"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

