insert into public.result_profiles (
  topic_id,
  profile_key,
  title,
  summary,
  strengths,
  blind_spots,
  growth_suggestions,
  base_prompt,
  matching_rules
) values (
  (select id from public.quiz_topics where slug = 'life-values'),
  'quadrant_ll',
  '關係使命者',
  '在人生排序、投入方向與選擇代價這件事上，你通常會先用關係與連結讀懂現場，再用意義與影響決定自己的節奏。你願意守住的東西本來就有重量，這份重量讓你更懂取捨。',
  ARRAY['你常能把人與在乎放進人生的重要位置。', '你也擅長願意把生命投向有價值感的事。', '遇到曖昧或混亂時，你比較容易找到一種對自己有交代的做法。']::text[],
  ARRAY['當你太依賴連結時，你有時會為了不失去連結，而延後自己的真實需求。', '當壓力升高時，你有時會為了值得感而忽略現實成本。', '你有時會把另一種同樣重要的需求，留到太後面才處理。']::text[],
  ARRAY['保留你的連結優勢，同時刻意借一點自主的視角。', '在做出反應前，留十秒問自己：我現在要的是安全感，還是真正適合我的方向？', '替影響留一點鬆動空間，通常會讓你更像自己，也更有餘裕。']::text[],
  '這個人在人格測驗主題「你的人生排序，最常被哪兩種價值拉扯？」中呈現 關係與連結 與 意義與影響 的組合。請用溫暖、像被理解的口吻補上一段 80 到 120 字的鏡像式洞察，避免診斷感。',
  '{"kind":"quadrant","axis1":"connection","axis2":"impact"}'::jsonb
) on conflict (topic_id, profile_key) do update set
  title = excluded.title,
  summary = excluded.summary,
  strengths = excluded.strengths,
  blind_spots = excluded.blind_spots,
  growth_suggestions = excluded.growth_suggestions,
  base_prompt = excluded.base_prompt,
  matching_rules = excluded.matching_rules;

